sys_script_include.script:
var LearningRecommendationEngine = Class.create();

LearningRecommendationEngine.prototype = {

    initialize: function() {},

    generate: function(profileId) {

        // Remove old recommendations

        var oldRec = new GlideRecord(
            'x_1920001_careeros_learning_recommendation'
        );

        oldRec.addQuery('profile', profileId);
        oldRec.query();

        while (oldRec.next()) {
            oldRec.deleteRecord();
        }

        // Read all open skill gaps

        var gapGR = new GlideRecord(
            'x_1920001_careeros_skill_gap'
        );

        gapGR.addQuery('profile', profileId);
        gapGR.addQuery('status', 'open');
        gapGR.query();

        while (gapGR.next()) {

            var skillName =
                gapGR.missing_skill.getDisplayValue();

            var rec =
                new GlideRecord(
                    'x_1920001_careeros_learning_recommendation'
                );

            rec.initialize();

            rec.profile = profileId;
            rec.skill_gap = gapGR.sys_id;
            rec.skill = gapGR.missing_skill;

            // Dynamic recommendations

            if (skillName == 'Flow Designer') {

                rec.course_name =
                    'Flow Designer Fundamentals';

                rec.provider = 'servicenow';

                rec.course_url =
                    'https://nowlearning.servicenow.com';

                rec.difficulty = 'intermediate';
            }

            else if (skillName == 'IntegrationHub') {

                rec.course_name =
                    'IntegrationHub Fundamentals';

                rec.provider = 'servicenow';

                rec.course_url =
                    'https://nowlearning.servicenow.com';

                rec.difficulty = 'advanced';
            }

            else if (skillName == 'JavaScript') {

                rec.course_name =
                    'JavaScript Essentials';

                rec.provider = 'coursera';

                rec.course_url =
                    'https://www.coursera.org';

                rec.difficulty = 'beginner';
            }

            else {

                rec.course_name =
                    skillName + ' Fundamentals';

                rec.provider = 'youtube';

                rec.course_url =
                    'https://youtube.com';

                rec.difficulty = 'beginner';
            }

            rec.priority = gapGR.priority;
            rec.status = 'recommended';

            rec.insert();
        }
    },

    type: 'LearningRecommendationEngine'
};
